  for (const [x, y] of cells) {
    const neighbors = countLiveNeighbors(x, y, live);
    if (neighbors === 2 || neighbors === 3) {
      result.push([x, y]);
    }
  }

  const deadNeighbors = new Set<string>();
  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const key = `${x + dx},${y + dy}`;
      if (!live.has(key)) {
        deadNeighbors.add(key);
      }
    }
  }

  for (const key of deadNeighbors) {
    const [x, y] = key.split(",").map(Number);
    if (countLiveNeighbors(x, y, live) === 3) {
      result.push([x, y]);
    }
  }

  return result;
}

function countLiveNeighbors(x: number, y: number, live: Set<string>): number {
  return NEIGHBOR_OFFSETS.reduce(
    (count, [dx, dy]) => live.has(`${x + dx},${y + dy}`) ? count + 1 : count,
    0,
  );
}
```

Let me think about refactoring opportunities:

1. **Naming**: `deadNeighbors` - this is a bit misleading. It's the set of dead cells that are neighbors of live cells. Maybe `candidateCells` or `deadNeighborCells`? Actually, `deadNeighbors` is reasonably clear - these are dead cells that neighbor live cells and are candidates for reproduction. Let me keep it.

2. **Duplication**: The string key pattern `${x},${y}` is used in multiple places. I could extract a `toKey` helper. This would reduce duplication (Rule 3) and make it easier to change the key format.

3. **Mass reduction**: The code iterates over cells twice - once for survival and once for finding dead neighbors. I could potentially combine these, but that would make the code less clear.

Let me do the `toKey` extraction refactoring since it removes duplication:

```typescript
const toKey = (x: number, y: number) => `${x},${y}`;

